import{_ as e,o as t,c as s,a3 as i}from"./chunks/framework.C49Ar5GK.js";const k=JSON.parse('{"title":"扩展点地图：先选最小改动边界","description":"从配置、数据、奖励到采样器、算法、AgentLoop、训练与推理后端，系统梳理 veRL 的扩展层和验证责任","frontmatter":{"title":"扩展点地图：先选最小改动边界","description":"从配置、数据、奖励到采样器、算法、AgentLoop、训练与推理后端，系统梳理 veRL 的扩展层和验证责任","lesson":{"stage":"05 · 改造","order":19,"time":"45–60 分钟","level":"进阶","question":"想实现新任务或新算法时，应该改哪一层，怎样避免把局部需求变成框架分叉？"}},"headers":[],"relativePath":"customization/extension-map.md","filePath":"customization/extension-map.md","lastUpdated":null}'),n={name:"customization/extension-map.md"};function l(d,a,o,p,r,h){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="扩展点地图-先选最小改动边界" tabindex="-1">扩展点地图：先选最小改动边界 <a class="header-anchor" href="#扩展点地图-先选最小改动边界" aria-label="Permalink to &quot;扩展点地图：先选最小改动边界&quot;">​</a></h1><p>真正理解框架，不是知道哪里都能改，而是知道<strong>哪里不必改</strong>。同一个目标常有多条路径：格式分数可以写 reward；动态过滤可能属于 ReplayBuffer；多轮工具交互属于 AgentLoop；新的优势基线才进入算法层。</p><p>选择扩展点的原则：在能表达需求的前提下，选拥有最小契约、最容易单测、最少影响分布式状态的一层。</p><h2 id="先用人话-不要为了换裁判而重建体育馆" tabindex="-1">先用人话：不要为了换裁判而重建体育馆 <a class="header-anchor" href="#先用人话-不要为了换裁判而重建体育馆" aria-label="Permalink to &quot;先用人话：不要为了换裁判而重建体育馆&quot;">​</a></h2><p>如果只是更换评分规则，写 reward function；如果比赛流程加入工具交互，改 AgentLoop；如果参赛样本选择规则变化，改 sampler；只有目标函数本身变化，才碰 estimator/policy loss。</p><p>每向下走一层，获得更多控制，也承担更多责任：shape、mask、权重版本、进程导入、资源放置、失败清理和性能回归。</p><h2 id="九层扩展阶梯" tabindex="-1">九层扩展阶梯 <a class="header-anchor" href="#九层扩展阶梯" aria-label="Permalink to &quot;九层扩展阶梯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>适合解决什么</th><th>当前主要入口</th><th>最低验证责任</th></tr></thead><tbody><tr><td>1 配置</td><td>batch、长度、后端、并行、现有 recipe</td><td>Hydra override/component YAML</td><td>resolved config + one-step run</td></tr><tr><td>2 数据</td><td>新 schema、chat template、多模态预处理</td><td><code>RLHFDataset</code> / <code>data.custom_cls</code></td><td>schema、token 长度、截断测试</td></tr><tr><td>3 奖励</td><td>规则、verifier、RM、组合分数</td><td><code>reward.custom_reward_function</code> / Reward Loop</td><td>反例、超时、安全、人工审计</td></tr><tr><td>4 工具/交互</td><td>多轮、工具、环境反馈</td><td><code>AgentLoopBase</code> / tool config</td><td>token 连续性、终止、资源释放</td></tr><tr><td>5 采样</td><td>过滤、优先级、staleness、oversampling</td><td><code>ReplayBuffer</code> subclass</td><td>完整 prompt group、不偏置/偏置说明</td></tr><tr><td>6 训练时序</td><td>step 前后动作、同步/异步生命周期</td><td>V1 trainer hooks/subclass</td><td>状态机、异常清理、同步语义</td></tr><tr><td>7 算法</td><td>新 advantage、policy loss、baseline</td><td>registries in <code>core_algos.py</code></td><td>tiny tensor 等式、mask、finite、梯度</td></tr><tr><td>8 Agent 框架</td><td>替换整套 rollout 调度</td><td>custom AgentLoopManager</td><td>非阻塞提交、TQ trajectory 契约</td></tr><tr><td>9 后端/硬件</td><td>新推理引擎、训练 engine、芯片</td><td>external module/plugin registries</td><td>分布式集成、权重同步、性能/精度</td></tr></tbody></table><p>下面不是 API 百科，而是帮助你做边界判断。</p><h2 id="_1–3-多数任务改造到这里已经够了" tabindex="-1">1–3：多数任务改造到这里已经够了 <a class="header-anchor" href="#_1–3-多数任务改造到这里已经够了" aria-label="Permalink to &quot;1–3：多数任务改造到这里已经够了&quot;">​</a></h2><h3 id="只改配置" tabindex="-1">只改配置 <a class="header-anchor" href="#只改配置" aria-label="Permalink to &quot;只改配置&quot;">​</a></h3><p>现有 estimator、policy loss、rollout backend 和 model engine 能组合出目标时，优先写一个可审计的 recipe YAML/shell，不要复制 trainer。先保存 resolved config，确认角色联动。</p><h3 id="自定义数据集" tabindex="-1">自定义数据集 <a class="header-anchor" href="#自定义数据集" aria-label="Permalink to &quot;自定义数据集&quot;">​</a></h3><p>当默认 <code>RLHFDataset</code> 无法表达字段或预处理时，用：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  custom_cls</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/shared/my_dataset.py</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">MyDataset</span></span></code></pre></div><p>扩展前先问：是否只需在 Parquet 预处理时新增 <code>extra_info</code>？能离线完成的工作不必放进每个 dataloader worker。</p><h3 id="自定义-reward" tabindex="-1">自定义 reward <a class="header-anchor" href="#自定义-reward" aria-label="Permalink to &quot;自定义 reward&quot;">​</a></h3><p>通过 path/name 加载纯函数，适合大多数新任务。它的契约是 response、ground truth、data source 与 extra info，不需要知道 actor 如何分片。详见<a href="/losh_has_blog/verl-learning/practice/reward-function">写一个可靠奖励函数</a>。</p><h2 id="_4-改变-模型如何与世界互动" tabindex="-1">4：改变“模型如何与世界互动” <a class="header-anchor" href="#_4-改变-模型如何与世界互动" aria-label="Permalink to &quot;4：改变“模型如何与世界互动”&quot;">​</a></h2><p>内置工具能力已支持函数工具和有状态工具。只有内置 ToolAgentLoop 无法表达状态机时，才继承 <code>AgentLoopBase</code> 并实现 <code>run()</code>。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyAgentLoop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AgentLoopBase</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    async</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(self, sampling_params, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dataset_fields) -&gt; AgentLoopOutput:</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        ...</span></span></code></pre></div><p>关键不变量：</p><ul><li>优先 token-in/token-out；不要 decode 后再 encode 造成轨迹 token 与 log-prob 对不齐；</li><li>明确 EOS、最大轮次、工具异常和取消时如何终止；</li><li>归还 <code>response_ids</code>、<code>response_mask</code>、log-prob 与 reward 所需字段；</li><li>sandbox、网络、文件和凭据都有资源/安全边界；</li><li>任一 coroutine 失败不会让同组永远停在 running。</li></ul><p><a href="https://verl.readthedocs.io/en/latest/advance/agent_loop.html" target="_blank" rel="noreferrer">官方 Agent Loop 文档</a>提供了当前接口背景；实际实现仍以固定提交的 <code>experimental/agent_loop</code> 为准。</p><h2 id="_5-改变-哪些轨迹进入下一次更新" tabindex="-1">5：改变“哪些轨迹进入下一次更新” <a class="header-anchor" href="#_5-改变-哪些轨迹进入下一次更新" aria-label="Permalink to &quot;5：改变“哪些轨迹进入下一次更新”&quot;">​</a></h2><p>V1 的 <code>_build_replay_buffer()</code> 支持按路径加载 <code>ReplayBuffer</code> 子类：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">trainer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  v1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    sampler</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      custom_sampler</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        path</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/shared/my_sampler.py</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">MyReplayBuffer</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      sampler_kwargs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        min_reward_gap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.25</span></span></code></pre></div><p>自定义 <code>sample(global_steps, partition_id, batch_size)</code> 时，不只是在 list 中挑 key。你必须维护：</p><ul><li>prompt group 完整性（尤其 GRPO 的 n 个 session）；</li><li>finished/failure/pending 状态与清理；</li><li><code>global_steps</code> 和 staleness 约束；</li><li>padding tag 与有效样本计数；</li><li>返回 <code>KVBatchMeta</code> 和可解释的辅助指标；</li><li>被过滤轨迹的 TQ 生命周期，避免泄漏存储。</li></ul><p>动态采样会改变训练数据分布，它既是系统调度又是算法设计。把过滤率、难度/来源分布和 reward 方差加入 guardrail。</p><h2 id="_6-改变训练时序-先使用-hooks" tabindex="-1">6：改变训练时序，先使用 hooks <a class="header-anchor" href="#_6-改变训练时序-先使用-hooks" aria-label="Permalink to &quot;6：改变训练时序，先使用 hooks&quot;">​</a></h2><p>V1 基类提供：<code>on_init_end</code>、<code>on_train_begin/end</code>、<code>on_validate_begin/end</code>、<code>on_step_begin/end</code>、<code>on_sample_begin/end</code>。</p><p>适合：在固定边界记录指标、切换模型引擎状态、控制权重同步或实现 mode 生命周期差异。若只需 step 前后行为，不要复制整个 <code>fit()</code>；复制训练循环会让 checkpoint、validation、TQ clear 和未来修复全部分叉。</p><p>必须画出异常路径：hook 中途抛错时，LLM replicas、TransferQueue、后台 executor 和 checkpoint 状态如何收尾。</p><h2 id="_7-改变训练目标-拆成-advantage-与-loss" tabindex="-1">7：改变训练目标，拆成 advantage 与 loss <a class="header-anchor" href="#_7-改变训练目标-拆成-advantage-与-loss" aria-label="Permalink to &quot;7：改变训练目标，拆成 advantage 与 loss&quot;">​</a></h2><p>问两个问题：</p><ol><li>我改变的是“每条/每个 token 相对基线好多少”吗？进入 advantage registry。</li><li>我改变的是“给定 advantage 后怎样限制概率、聚合 token”吗？进入 policy loss registry。</li></ol><p>不要把 sampling、reward shaping、advantage 和 loss 全塞进一个大函数。这样无法分别做等价测试，也很难判断 ablation 在改变什么。</p><p>具体实现见<a href="./custom-algorithm">实现自定义算法</a>。</p><h2 id="_8-替换-agentloopmanager-是一条系统边界" tabindex="-1">8：替换 AgentLoopManager 是一条系统边界 <a class="header-anchor" href="#_8-替换-agentloopmanager-是一条系统边界" aria-label="Permalink to &quot;8：替换 AgentLoopManager 是一条系统边界&quot;">​</a></h2><p><code>TaskRunnerV1.init_agent_loop_manager()</code> 支持配置 fully-qualified class：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">+actor_rollout_ref.rollout.agent.agent_loop_manager_class</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=my_pkg.manager.MyAgentLoopManager</span></span></code></pre></div><p>自定义 manager 的核心契约不是“返回一个大 batch”，而是：<code>generate_sequences(prompts)</code> 非阻塞提交，并在完成后把 trajectory 字段与 tag 写入 TransferQueue。ReplayBuffer 会在另一侧等待可采样 group。</p><p>这适合接入已有 agent framework；若只是多轮工具逻辑，优先改 AgentLoop，不要先替换 manager。</p><h2 id="_9-新训练-推理后端使用外部模块入口" tabindex="-1">9：新训练/推理后端使用外部模块入口 <a class="header-anchor" href="#_9-新训练-推理后端使用外部模块入口" aria-label="Permalink to &quot;9：新训练/推理后端使用外部模块入口&quot;">​</a></h2><p>固定源码在 <code>verl/__init__.py</code> 读取：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> VERL_USE_EXTERNAL_MODULES</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">my_package.register</span></span></code></pre></div><p>模块导入时可向 rollout replica/server adapter、training engine 等 registry 注册实现。它必须在 driver 和所有 Ray worker 可导入；多机上依赖包、版本和环境变量要一致。</p><p>后端扩展责任远超“实现 generate”：还包括模型加载、并行拓扑、sleep/wake、KV cache、取消、健康检查、权重版本与 checkpoint engine 同步、dtype/数值一致性和故障清理。</p><h2 id="变更前写一张契约卡" tabindex="-1">变更前写一张契约卡 <a class="header-anchor" href="#变更前写一张契约卡" aria-label="Permalink to &quot;变更前写一张契约卡&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目标：我具体想改变什么可观察行为？</span></span>
<span class="line"><span>层级：为什么现有更上层扩展点不够？</span></span>
<span class="line"><span>输入：字段 / shape / dtype / device / 权重版本</span></span>
<span class="line"><span>输出：字段 / shape / tag / 指标</span></span>
<span class="line"><span>不变量：mask、分组、有限值、顺序、清理</span></span>
<span class="line"><span>失败：超时/异常/空结果怎样传播与回收？</span></span>
<span class="line"><span>测试：纯函数 → 组件 → one-step → A/B</span></span>
<span class="line"><span>回退：哪个开关能恢复基线？</span></span></code></pre></div><p>若“为什么更上层不够”写不出来，先停在更小边界。</p><h2 id="选择例子" tabindex="-1">选择例子 <a class="header-anchor" href="#选择例子" aria-label="Permalink to &quot;选择例子&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需求</th><th>推荐首选层</th><th>不应先做</th></tr></thead><tbody><tr><td>代码题接沙箱评分</td><td>reward + sandbox</td><td>改 PPOTrainer</td></tr><tr><td>同题全对/全错不训练</td><td>custom ReplayBuffer/recipe</td><td>在 policy loss 静默丢 token</td></tr><tr><td>新组内 baseline</td><td>advantage registry</td><td>新建完整 trainer</td></tr><tr><td>每条回答等权</td><td>policy loss aggregation</td><td>改 reward 数值补偿长度</td></tr><tr><td>新工具协议</td><td>Tool/AgentLoop</td><td>改 rollout engine kernel</td></tr><tr><td>接入已有 agent 平台</td><td>AgentLoopManager</td><td>把整个平台塞进 reward function</td></tr><tr><td>新推理引擎</td><td>external backend registry</td><td>在 trainer 中写大量 <code>if backend</code></td></tr></tbody></table><h2 id="通关检查" tabindex="-1">通关检查 <a class="header-anchor" href="#通关检查" aria-label="Permalink to &quot;通关检查&quot;">​</a></h2><p>选择你真实想做的一项改动，写契约卡并指出最小层级。然后列出改动会影响的三类指标：任务正确性、算法分布、系统资源。下一步如果目标是算法，进入<a href="./custom-algorithm">实现自定义算法</a>；如果目标是吞吐，进入<a href="./optimization-playbook">优化方法论</a>。</p>`,56)])])}const g=e(n,[["render",l]]);export{k as __pageData,g as default};
